import React, { useState, useRef, useEffect } from 'react';
import './App.css';
import 'bootstrap/dist/css/bootstrap.min.css';
import {
  Navbar,
  Nav,
  NavItem,
  Carousel,
  CarouselItem,
  CarouselControl,
  CarouselIndicators,
  CarouselCaption,
  Container,
  Card,
  CardText,
  CardTitle,
  CardBody,
  Button,
  CardLink,
  PopoverHeader, 
  PopoverBody,
  UncontrolledPopover
} from 'reactstrap';
import { Row, Col } from 'react-simple-flex-grid';
import "react-simple-flex-grid/lib/main.css";
import { Github, Facebook, Linkedin, FiletypeDocx } from 'react-bootstrap-icons';
import {SiCodeforces} from "react-icons/si"
import {DiPython, DiJava, DiJavascript1, DiBootstrap, DiCss3, DiDocker, DiHaskell, DiHtml5, DiLinux, DiReact, DiScala, DiSwift, DiVisualstudio} from "react-icons/di"

import london from "./images/London.JPG"
import kenya from "./images/Kenya.JPG"
import swiss1 from "./images/Switzerland1.JPG"
import swiss2 from "./images/Switzerland2.JPG"
import tejas from "./images/Tejas.jpg"
import aqaba from "./images/Aqaba.JPG"
import cappadocia from "./images/Cappadocia.JPG"
import pestleplus from "./images/Pestleplus.jpeg"
import tracr from "./images/Tracr.png"
import backgroundnoise from "./images/BackgroundNoise.png"
import sudoku from "./images/Sudoku.png"
import gyroscope from "./images/Gyroscope.png"
import tejasviolin from "./images/Tejasviolin.png"

const projitems = [
  {
    imgsrc: pestleplus,
    title: "Pestle+",
    text: "Works on top of an IB question bank website called Pestle. Uses an NLP-based algorithm that is a combination of sentiment analysis and named entity recognition on examiner’s remarks to rank questions by difficulty. Additionally, uses keyword extraction to find related questions for each question.",
    url: "https://chrome.google.com/webstore/detail/pestle%20/lcpbagfnfnjgmmjegmjbmhbkjedgcioi",
  },
  {
    imgsrc: tracr,
    title: "TRACR: Scheduling App",
    text: "Led a team of four to develop an app to schedule time to work on assignments, given the length and due date of the assignments, a list of working hours, and other preferences. Learned Swift, SwiftUI, the Google Classroom API, and designed a complex scheduling algorithm. Beta tested in school.",
    url: "https://github.com/krishte/TRACR",
  },
  {
    imgsrc: backgroundnoise,
    title: "Background Noise Cancellation",
    text: "Wrote a Python program to remove background noise from audio files utilizing short-time Fourier transforms and deep-learning (TensorFlow), Learned basics of digital signal processing and types of neural networks. Met with minimal success when background noise was from a fan.",
    url: "https://github.com/krishte/BackNoiseCanc",
  },
  {
    imgsrc: sudoku,
    title: "Sudoku Solver",
    text: "A Java program to solve sudokus with a GUI made using JavaFX. The program employs traditional sudoku solving techniques that one would use when solving a sudoku by hand in addition to a brute force guessing method if the previous method is unable to make any progress on the sudoku.",
    url: "https://github.com/krishte/SudokuSolver",
  },
  { 
    imgsrc: gyroscope,
    title: "WatchMacController",
    text: "A pair of apps that run on Mac and Apple Watch so that the Apple Watch can be used to control the Mac",
    url: "https://github.com/krishte/WatchMacController",
  },
]

const langitems = [
  {
    target: "Popover1",
    title: "Python",
    body: "hello" 
  },
  {
    target: "Popover2",
    title: "Java",
    body: "hello" 
  },
  {
    target: "Popover3",
    title: "Javascript",
    body: "hello" 
  },
  {
    target: "Popover4",
    title: "Bootstrap",
    body: "hello" 
  },
  {
    target: "Popover5",
    title: "CSS3",
    body: "hello" 
  },
  {
    target: "Popover6",
    title: "Docker",
    body: "hello" 
  },
  {
    target: "Popover7",
    title: "Haskell",
    body: "hello" 
  },
  {
    target: "Popover8",
    title: "HTML5",
    body: "hello" 
  },
  {
    target: "Popover9",
    title: "Linux",
    body: "hello" 
  },
  {
    target: "Popover10",
    title: "React",
    body: "hello" 
  },
  {
    target: "Popover11",
    title: "Scala",
    body: "hello" 
  },
  {
    target: "Popover12",
    title: "Swift",
    body: "hello" 
  },
  {
    target: "Popover13",
    title: "VSCode",
    body: "hello" 
  }
]

const imgitems = [
  {
    src: london,
    caption: 'London, United Kingdom',
    key: 1,
  },  
  {
    src: kenya,
    caption: 'Masai Mara National Reserve, Kenya',
    key: 2,
  },
  {
    src: swiss1,
    caption: 'Grindelwald, Switzerland',
    key: 3,
  },
  {
    src: swiss2,
    caption: 'Kandersteg, Switzerland',
    key: 4,
  },
  {
    src: aqaba,
    caption: 'Aqaba, Jordan',
    key: 5,
  },
  {
    src: cappadocia,
    caption: 'Cappadocia, Turkey',
    key: 6,
  },
];

function App() {


  const [activeIndex, setActiveIndex] = useState(0);
  const [animating, setAnimating] = useState(false);
  const [navbarheight, setNavbarHeight] = useState(80);

  const skillsize = 150

  const next = () => {
    if (animating) return;
    const nextIndex = activeIndex === imgitems.length - 1 ? 0 : activeIndex + 1;
    setActiveIndex(nextIndex);
  };

  const previous = () => {
    if (animating) return;
    const nextIndex = activeIndex === 0 ? imgitems.length - 1 : activeIndex - 1;
    setActiveIndex(nextIndex);
  };

  const goToIndex = (newIndex) => {
    if (animating) return;
    setActiveIndex(newIndex);
  };

  const slides = imgitems.map((item) => {
    return (
      <CarouselItem
        onExiting={() => setAnimating(true)}
        onExited={() => setAnimating(false)}
        key={item.src}
        className="maxwidth"
      >
        <Row>
          <Col xl={{span:6, offset:3}} lg={{span:6, offset:3}} md={{span:8, offset:2}} sm={{span:10, offset:1}} xs={{span:10, offset:1}}>
           <img src={item.src} alt={item.caption} className="img-fluid rounded-5"/>
          </Col>
        </Row>
        <CarouselCaption
          captionText={item.caption}
        />
      </CarouselItem>
    );
  });

  const projects = projitems.map((item) => {
    return (
      <Col xl={{span:3}} lg={{span:4}} md={{span:4}} sm={{span:6}} xs={{span:12}} style={{paddingBottom:"40px"}}>
        <Card
          inverse
          className='bg-dark shadow-lg projectcard'
        >
          <img
            alt="Sample"
            src={item.imgsrc}
            className="img-fluid"
          />
          <CardBody>
            <CardTitle tag="h5">
              {item.title}
            </CardTitle>
            <CardText>
              {item.text}
            </CardText>
            <CardLink href={item.url}>
              Learn more
            </CardLink>
          </CardBody>
        </Card>
      </Col>
    )
  });

  const languages = langitems.map((item) => {
    return (
      <UncontrolledPopover
        flip
        placement="top"
        target={item.target}
        trigger="hover"
      >
        <PopoverHeader>
          {item.title}
        </PopoverHeader>
        {/* <PopoverBody>
          {item.body}
        </PopoverBody> */}
      </UncontrolledPopover>
    )
  })

  const handleScroll = () => {
    const position = window.pageYOffset;
    if (position===0) {
      setNavbarHeight(80)
    }
    else
    {
      setNavbarHeight(65)
    }
  };

  useEffect(() => {
    window.addEventListener('scroll', handleScroll, { passive: true });

    return () => {
        window.removeEventListener('scroll', handleScroll);
    };
  }, []);

  const aboutRef = useRef();
  const skillsRef = useRef();
  const projectsRef = useRef();
  const musicRef = useRef();



  return (
    <div className="App">
      <Container className="navbarstyle">
        <Navbar color="dark" dark fixed="top" style={{height:navbarheight, transition: "0.3s"}}>
          <Button style={{paddingLeft:"10px"}}
            onClick={() =>
              window.scrollTo({
                left: 0,
                top: 0,
                behavior: "smooth",
              })
            }
            color="dark"
            >
              <h5 style={{paddingTop:"5px"}}>Tejas Krishnan</h5>
          </Button>
          <Nav>
            <NavItem>
              <Button        
                onClick={() =>
                  window.scrollTo({
                    left: 0,
                    top: aboutRef.current.offsetTop-navbarheight,
                    behavior: "smooth",
                  })
                }
                color="dark"
              >
                About
              </Button>
            </NavItem>
            <NavItem>
              <Button        
                onClick={() =>
                  window.scrollTo({
                    left: 0,
                    top: skillsRef.current.offsetTop-navbarheight,
                    behavior: "smooth",
                  })
                }
                color="dark"
              >
                Skills
              </Button>
            </NavItem>
            <NavItem>
              <Button        
                onClick={() =>
                  window.scrollTo({
                    left: 0,
                    top: projectsRef.current.offsetTop-navbarheight,
                    behavior: "smooth",
                  })
                }
                color="dark"
              >
                Projects
              </Button>
            </NavItem>
            <NavItem>
              <Button        
                onClick={() =>
                  window.scrollTo({
                    left: 0,
                    top: musicRef.current.offsetTop-navbarheight,
                    behavior: "smooth",
                  })
                }
                color="dark"
              >
                Music
              </Button>
            </NavItem>
          </Nav>
        </Navbar>
      </Container>
      <Container fluid className="pagediv" style={{paddingTop:navbarheight+20}}>
        <div style={{padding:"20px"}}>
          <Carousel
          activeIndex={activeIndex}
          next={next}
          previous={previous}
          >
            <CarouselIndicators
              items={imgitems}
              activeIndex={activeIndex}
              onClickHandler={goToIndex}
            />
            {slides}
            <CarouselControl
              direction="prev"
              directionText="Previous"
              onClickHandler={previous}
            />
            <CarouselControl
              direction="next"
              directionText="Next"
              onClickHandler={next}
            />
          </Carousel>
        </div>
      </Container>
      <Container fluid className="pagediv2">
        <div style={{display:"flex",justifyContent:"center"}} ref={aboutRef}>
          <Row style={{padding:"20px"}} gutter={40}>
              <Col xl={{span:5, offset:2}} lg={{span:5, offset:2}} md={{span:6, offset:1}} sm={{span:7}} xs={{span:12}}>
                <h1 style={{textAlign:"left"}}>About Me</h1>
                <p style={{textAlign:"left", paddingBottom:"10px"}}>Hi! My name is Tejas and I'm a first-year mathematics and computer science student at the University of Oxford. I'm passionate about software development with experience developing IOS Apps and Chrome Extensions, and I'm an avid competitive programmer well-versed in algorithms and data structures. I've pursued programming projects in deep-learning, web scraping, automation, NLP and NLU, and web design. My hobbies include playing tennis and the violin, the latter of which I've done for over a decade. I also like to travel, and all the photos above are taken by me. </p>
                <Row style={{paddingBottom:"20px"}} justify="space-around" align="middle">
                  <Col> 
                    <a href="https://github.com/krishte" ><Github className='link-color' size="50px"/></a>
                  </Col>
                  <Col> 
                    <a href="https://www.linkedin.com/in/tejas-krishnan-434b90218/"><Linkedin className='link-color' size="50px"/></a>
                  </Col>
                  <Col >
                    <a href="www.google.com"><Facebook className='link-color' size="50px"/></a>
                  </Col>
                  <Col>
                    <a href="www.google.com"><FiletypeDocx className='link-color' size="50px"/></a>
                  </Col>
                  <Col>
                    <a href="https://codeforces.com/profile/TechNoLogic"><SiCodeforces className='link-color' size="50px"/></a>
                  </Col>
                </Row>
              </Col>
              <Col xl={{span:3}} lg={{span:3}} md={{span:4}} sm={{span:5}} xs={{span:12}}>     
                <img src={tejas} alt="hello" className='rounded-4 img-fluid'/>                
              </Col>
          </Row>
        </div>
      </Container>
      <Container fluid className="pagediv">
        <div style={{display:"flex",justifyContent:"center", padding:"20px"}} ref={skillsRef}>
          <Col>
            <h1 style={{textAlign:"middle"}}>Skills</h1>
            <Row style={{padding:"20px"}} gutter={40} align="middle">
              <Col style={{padding:"20px"}}> 
                <DiPython id="Popover1" className="link-color"  size={skillsize}/>
                {languages}
              </Col>
              <Col style={{padding:"20px"}}> 
                <DiJava id="Popover2" size={skillsize} className='link-color'/>
              </Col>
              <Col style={{padding:"20px"}}> 
                <DiJavascript1 id="Popover3" size={skillsize} className='link-color'/>
              </Col>
              <Col style={{padding:"20px"}}> 
                <DiBootstrap id="Popover4" size={skillsize} className='link-color'/>
              </Col>
              <Col style={{padding:"20px"}}> 
                <DiCss3 id="Popover5" size={skillsize} className='link-color'/>
              </Col>
              <Col style={{padding:"20px"}}> 
                <DiDocker id="Popover6" size={skillsize} className='link-color'/>
              </Col>
              <Col style={{padding:"20px"}}> 
                <DiHaskell id="Popover7" size={skillsize} className='link-color'/>
              </Col>
              <Col style={{padding:"20px"}}> 
                <DiHtml5 id="Popover8" size={skillsize} className='link-color'/>
              </Col>
              <Col style={{padding:"20px"}}> 
                <DiLinux id="Popover9" size={skillsize} className='link-color'/>
              </Col>
              <Col style={{padding:"20px"}}> 
                <DiReact id="Popover10" size={skillsize} className='link-color'/>
              </Col>
              <Col style={{padding:"20px"}}> 
                <DiScala id="Popover11" size={skillsize} className='link-color'/>
              </Col>
              <Col style={{padding:"20px"}}> 
                <DiSwift id="Popover12" size={skillsize} className='link-color'/>
              </Col>
              <Col style={{padding:"20px"}}> 
                <DiVisualstudio id="Popover13" size={skillsize} className='link-color'/>
              </Col>
            </Row>
          </Col>
        </div>
      </Container>
      <Container fluid className="pagediv2">
        <div style={{display:"flex",justifyContent:"center", padding:"20px"}} ref={projectsRef}>
          <Col>
            <h1>Projects</h1>
            <Row style={{padding:"20px"}} gutter={40} align="top">
              {projects}
            </Row>
          </Col>
        </div>
      </Container>
      <Container fluid className="pagediv">
        <div style={{display:"flex",justifyContent:"center", padding:"20px"}} ref={musicRef}>
          <Col >
            <h1>Music</h1>
            <img src={tejasviolin} alt="hello"className="img-fluid maxwidth rounded-5" style={{width:"100%"}}/>
          </Col>
        </div>
      </Container>
    </div>
  );
}
export default App;
